PRAGMA foreign_keys = ON;

CREATE TABLE prices (
  id INTEGER PRIMARY KEY,
  sku TEXT NOT NULL,
  amount_cents INTEGER NOT NULL CHECK (amount_cents >= 0),
  valid_from TEXT NOT NULL,
  valid_to TEXT,
  CHECK (valid_to IS NULL OR valid_from < valid_to)
);

CREATE TABLE price_requests (
  request_id TEXT PRIMARY KEY,
  sku TEXT NOT NULL,
  at_time TEXT NOT NULL
);

CREATE TRIGGER prices_no_overlap
BEFORE INSERT ON prices
WHEN EXISTS (
  SELECT 1
  FROM prices AS existing
  WHERE existing.sku = NEW.sku
    AND existing.valid_from <= COALESCE(NEW.valid_to, '9999-12-31T23:59:59Z')
    AND NEW.valid_from <= COALESCE(existing.valid_to, '9999-12-31T23:59:59Z')
)
BEGIN
  SELECT RAISE(ABORT, 'overlapping price interval');
END;

